mapper.select:
select id, task_code, task_name, handler_code, cron_expression, execution_mode,
       status, description, last_fire_at, next_fire_at, created_at, updated_at
from scheduled_tasks


        and task_code = #{taskCode}


        and status = #{status}


        and handler_code = #{handlerCode}


order by id asc

mapper.insert:
insert into scheduled_tasks(
    task_code, task_name, handler_code, cron_expression,
    execution_mode, status, description
) values(
    #{taskCode}, #{taskName}, #{handlerCode}, #{cronExpression},
    #{executionMode}, #{status}, #{description}
)

mapper.update:
update scheduled_tasks
set next_fire_at = #{nextFireAt}
where id = #{id}

mapper.insert:
insert into scheduled_task_runs(
    task_id, task_code, task_name, execution_mode, node_id, trigger_type,
    status, start_time, end_time, duration_ms, affected_rows, error_msg
) values(
    #{taskId}, #{taskCode}, #{taskName}, #{executionMode}, #{nodeId}, #{triggerType},
    #{status}, #{startTime}, #{endTime}, #{durationMs}, #{affectedRows}, #{errorMsg}
)

mapper.select:
select id, task_id, task_code, task_name, execution_mode, node_id, trigger_type,
       status, start_time, end_time, duration_ms, affected_rows, error_msg, created_at
from scheduled_task_runs


        and task_code = #{taskCode}


        and status = #{status}


        and trigger_type = #{triggerType}


order by start_time desc, id desc
